{
  "name": "project-management",
  "version": "1.0.0",
  "description": "A simple project management API",
  "main": "src/app.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "node --test tests/oracle.test.js"
  },
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "supertest": "^6.3.3"
  }
}

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const express = require('express');
const projectService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projects = projectService.getAllProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  const project = projectService.createProject(name);
  res.status(201).json({ project });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const store = require('./store');

function getAllProjects() {
  return Object.values(store.projects);
}

function createProject(name) {
  const id = randomUUID();
  const project = { id, name, members: [], tasks: [] };
  store.projects[id] = project;
  return project;
}

module.exports = {
  getAllProjects,
  createProject,
};

const express = require('express');
const memberService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'UserId and role are required');
  }
  const member = memberService.addMember(projectId, userId, role);
  if (!member) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ member });
});

module.exports = router;

const projectService = require('../projects/service');
const { randomUUID } = require('node:crypto');

function addMember(projectId, userId, role) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const member = { id: randomUUID(), userId, role };
  project.members.push(member);
  return member;
}

module.exports = {
  addMember,
};

const express = require('express');
const taskService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const tasks = taskService.getTasksByProject(projectId);
  if (!tasks) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  const statusFilter = req.query.status;
  if (statusFilter) {
    const filteredTasks = tasks.filter(task => task.status === statusFilter);
    res.json({ tasks: filteredTasks });
  } else {
    res.json({ tasks });
  }
});

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  const task = taskService.createTask(projectId, name);
  if (!task) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }
  const task = taskService.updateTaskStatus(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;

const projectService = require('../projects/service');
const { randomUUID } = require('node:crypto');

function getTasksByProject(projectId) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  return project.tasks;
}

function createTask(projectId, name) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = { id: randomUUID(), name, status: 'todo' };
  project.tasks.push(task);
  return task;
}

function updateTaskStatus(projectId, taskId, status) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
}

module.exports = {
  getTasksByProject,
  createTask,
  updateTaskStatus,
};

const express = require('express');
const commentService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const comments = commentService.getCommentsByTask(projectId, taskId);
  if (!comments) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ comments });
});

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');
  }
  const comment = commentService.createComment(projectId, taskId, message);
  if (!comment) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.status(201).json({ comment });
});

module.exports = router;

const projectService = require('../projects/service');
const { randomUUID } = require('node:crypto');

function getCommentsByTask(projectId, taskId) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task || !task.comments) {
    return [];
  }
  return task.comments;
}

function createComment(projectId, taskId, message) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  if (!task.comments) {
    task.comments = [];
  }
  const comment = { id: randomUUID(), message };
  task.comments.push(comment);
  return comment;
}

module.exports = {
  getCommentsByTask,
  createComment,
};

function sendError(res, statusCode, errorCode, message) {
  res.status(statusCode).json({ error: { code: errorCode, message } });
}

module.exports = {
  sendError,
};
